UPDATE players SET cardType = 'diamond' WHERE overall >= 90;
UPDATE players SET cardType = 'gold' WHERE overall >= 75 AND overall < 90;
UPDATE players SET cardType = 'bronze' WHERE overall < 75;

-- Verificar distribuição
SELECT cardType, COUNT(*) as total, MIN(overall) as min_overall, MAX(overall) as max_overall
FROM players GROUP BY cardType ORDER BY max_overall DESC;

